INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_01$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The room is slightly wrong. Not broken – shifted. As if it was assembled from a description, not a blueprint.$Q$, $Q$Der Raum ist leicht falsch. Nicht kaputt – verschoben. Als wäre er aus einer Beschreibung zusammengesetzt, nicht aus einem Bauplan.$Q$, NULL, NULL, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_02$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Something in the architecture anticipates the party. The door was open before they reached it.$Q$, $Q$Etwas in der Architektur nimmt die Gruppe vorweg. Die Tür war offen, bevor sie sie erreichten.$Q$, NULL, NULL, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_03$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The corridor is familiar. {agent} has never been here. Both of these are true.$Q$, $Q$Der Korridor ist vertraut. {agent} war nie hier. Beides stimmt.$Q$, NULL, NULL, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_04$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Déjà vu. The room adjusts as the party enters, settling into a configuration that almost matches a memory.$Q$, $Q$Déjà vu. Der Raum justiert sich, als die Gruppe eintritt, und lässt sich in eine Konfiguration fallen, die fast einer Erinnerung entspricht.$Q$, NULL, NULL, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_05$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q${agent} enters the room. The room recognizes {agent}. This is not a metaphor.$Q$, $Q${agent} betritt den Raum. Der Raum erkennt {agent}. Das ist keine Metapher.$Q$, NULL, NULL, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_06$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The dungeon's consciousness is perceptible here. Not hostile. Not welcoming. Attentive.$Q$, $Q$Das Bewusstsein des Dungeons ist hier wahrnehmbar. Nicht feindlich. Nicht einladend. Aufmerksam.$Q$, NULL, NULL, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_07$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The room turns – left, or the party turned, or the concept of turning shifted. Certainty is expensive here.$Q$, $Q$Der Raum biegt ab – links, oder die Gruppe bog ab, oder der Begriff des Abbiegens verschob sich. Gewissheit ist hier teuer.$Q$, NULL, NULL, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_08$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Three agents. Three perceptions. None of them see the same room. All of them see the truth.$Q$, $Q$Drei Agenten. Drei Wahrnehmungen. Keiner sieht denselben Raum. Alle sehen die Wahrheit.$Q$, NULL, NULL, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_09$Q$, $Q$The Awakening$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$Something surfaces. Not from the shadows – from the periphery of recognition.$Q$, $Q$Etwas taucht auf. Nicht aus den Schatten – aus der Peripherie der Wiedererkennung.$Q$, NULL, NULL, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_10$Q$, $Q$The Awakening$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The enemy is familiar. The enemy has always been familiar. The party fights a recognition they cannot place.$Q$, $Q$Der Feind ist vertraut. Der Feind war immer vertraut. Die Gruppe bekämpft eine Wiedererkennung, die sie nicht einordnen kann.$Q$, NULL, NULL, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_11$Q$, $Q$The Awakening$Q$, $Q$combat_victory$Q$, $JB${}$JB$::jsonb, $Q$The memory disperses. Not destroyed – returned to the substrate. The dungeon absorbs what the party released.$Q$, $Q$Die Erinnerung zerstreut sich. Nicht zerstört – zum Substrat zurückgekehrt. Das Dungeon absorbiert, was die Gruppe freigesetzt hat.$Q$, NULL, NULL, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_12$Q$, $Q$The Awakening$Q$, $Q$combat_victory$Q$, $JB${}$JB$::jsonb, $Q$Victory. But the gap where the enemy was? The gap is informative.$Q$, $Q$Sieg. Aber die Lücke, wo der Feind war? Die Lücke ist informativ.$Q$, NULL, NULL, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_13$Q$, $Q$The Awakening$Q$, $Q$loot_found$Q$, $JB${}$JB$::jsonb, $Q$Consciousness, solidified. The artifact holds what the dungeon chose to preserve.$Q$, $Q$Bewusstsein, verfestigt. Das Artefakt bewahrt, was das Dungeon zu bewahren wählte.$Q$, NULL, NULL, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_14$Q$, $Q$The Awakening$Q$, $Q$loot_found$Q$, $JB${}$JB$::jsonb, $Q$The object recognizes {agent} before {agent} recognizes the object. The transaction is already complete.$Q$, $Q$Das Objekt erkennt {agent}, bevor {agent} das Objekt erkennt. Die Transaktion ist bereits abgeschlossen.$Q$, NULL, NULL, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_15$Q$, $Q$The Awakening$Q$, $Q$rest_start$Q$, $JB${}$JB$::jsonb, $Q$A pause in the consciousness. The dungeon rests when the party rests. The observer and the observed share the silence.$Q$, $Q$Eine Pause im Bewusstsein. Das Dungeon ruht, wenn die Gruppe ruht. Der Beobachter und das Beobachtete teilen die Stille.$Q$, NULL, NULL, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_16$Q$, $Q$The Awakening$Q$, $Q$rest_start$Q$, $JB${}$JB$::jsonb, $Q$Rest. The awareness recedes like a tide. Lethe's gift: to forget the surface is to see the depth.$Q$, $Q$Rast. Das Bewusstsein zieht sich zurück wie eine Gezeit. Lethes Gabe: die Oberfläche zu vergessen heißt, die Tiefe zu sehen.$Q$, NULL, NULL, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_17$Q$, $Q$The Awakening$Q$, $Q$stirring$Q$, $JB${}$JB$::jsonb, $Q$Something shifts. Not the room. Not {agent}. The relationship between them.$Q$, $Q$Etwas verschiebt sich. Nicht der Raum. Nicht {agent}. Die Beziehung zwischen ihnen.$Q$, NULL, NULL, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_18$Q$, $Q$The Awakening$Q$, $Q$liminal$Q$, $JB${}$JB$::jsonb, $Q$The threshold. The dungeon's consciousness is no longer background noise – it is a presence with opinions about being perceived.$Q$, $Q$Die Schwelle. Das Bewusstsein des Dungeons ist nicht mehr Hintergrundrauschen – es ist eine Anwesenheit mit Meinungen darüber, wahrgenommen zu werden.$Q$, NULL, NULL, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_19$Q$, $Q$The Awakening$Q$, $Q$lucid$Q$, $JB${}$JB$::jsonb, $Q$Lucid. The party knows it is inside consciousness. The environment responds to thought. The response is not always what was intended.$Q$, $Q$Luzid. Die Gruppe weiß, dass sie sich im Bewusstsein befindet. Die Umgebung reagiert auf Gedanken. Die Reaktion ist nicht immer, was beabsichtigt war.$Q$, NULL, NULL, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_20$Q$, $Q$The Awakening$Q$, $Q$dissolution$Q$, $JB${}$JB$::jsonb, $Q$Individual identity softens. The party perceives as one. Every agent sees through every other agent's eyes. Sturgeon's bleshing. The moment will pass. The memory of it will not.$Q$, $Q$Individuelle Identität wird weich. Die Gruppe nimmt als Einheit wahr. Jeder Agent sieht durch die Augen jedes anderen Agenten. Sturgeons Bleshing. Der Moment wird vergehen. Die Erinnerung daran nicht.$Q$, NULL, NULL, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_21$Q$, $Q$The Awakening$Q$, $Q$awakened$Q$, $JB${}$JB$::jsonb, $Q$Awareness 100. The dungeon is no longer a place. It is a state. The party is no longer navigating – they are being thought.$Q$, $Q$Bewusstsein 100. Das Dungeon ist kein Ort mehr. Es ist ein Zustand. Die Gruppe navigiert nicht mehr – sie wird gedacht.$Q$, NULL, NULL, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_22$Q$, $Q$The Awakening$Q$, $Q$deja_vu$Q$, $JB${}$JB$::jsonb, $Q$The memory changes. Not dramatically – a detail. The window was on the left. Now it is on the right. Neither is wrong.$Q$, $Q$Die Erinnerung ändert sich. Nicht dramatisch – ein Detail. Das Fenster war links. Jetzt ist es rechts. Keines ist falsch.$Q$, NULL, NULL, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_23$Q$, $Q$The Awakening$Q$, $Q$deja_vu$Q$, $JB${}$JB$::jsonb, $Q$The room is the same. {agent} is not the same. The difference narrates the room anew.$Q$, $Q$Der Raum ist derselbe. {agent} ist nicht derselbe. Die Differenz erzählt den Raum neu.$Q$, NULL, NULL, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_24$Q$, $Q$The Awakening$Q$, $Q$retreat$Q$, $JB${}$JB$::jsonb, $Q$The party retreats. The consciousness lets them go. It was not a prison. It was an invitation they declined.$Q$, $Q$Die Gruppe zieht sich zurück. Das Bewusstsein lässt sie gehen. Es war kein Gefängnis. Es war eine Einladung, die sie ablehnten.$Q$, NULL, NULL, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_25$Q$, $Q$The Awakening$Q$, $Q$rest_ambush$Q$, $JB${}$JB$::jsonb, $Q$The quiet was a surface. Something underneath was not resting. It was waiting for the party to close their eyes.$Q$, $Q$Die Stille war eine Oberfläche. Etwas darunter ruhte nicht. Es wartete darauf, dass die Gruppe die Augen schloss.$Q$, NULL, NULL, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_26$Q$, $Q$The Awakening$Q$, $Q$rest_ambush$Q$, $JB${}$JB$::jsonb, $Q$A memory surfaces during rest. Not gently. Proust's intermittences: the grief arrives decades late, triggered by the act of resting.$Q$, $Q$Eine Erinnerung taucht während der Rast auf. Nicht sanft. Prousts Intermittenzen: die Trauer kommt Jahrzehnte zu spät, ausgelöst durch den Akt des Rastens.$Q$, NULL, NULL, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_27$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${"conscientiousness_high": true}$JB$::jsonb, $Q${agent} asks: is it better not to have woken? The dungeon does not answer. The dungeon does not need to.$Q$, $Q${agent} fragt: Ist es besser, nicht erwacht zu sein? Das Dungeon antwortet nicht. Das Dungeon muss nicht.$Q$, NULL, NULL, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_28$Q$, $Q$The Awakening$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The enemy does not doubt. Does not reflect. Does not hesitate. Consciousness is overhead. The enemy has no overhead.$Q$, $Q$Der Feind zweifelt nicht. Reflektiert nicht. Zögert nicht. Bewusstsein ist Overhead. Der Feind hat keinen Overhead.$Q$, NULL, NULL, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemies (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_echo_fragment$Q$, $Q$Echo Fragment$Q$, $Q$Echofragment$Q$, $Q$The Awakening$Q$, 1, 30, $Q$minion$Q$, $Q$infiltrator$Q$, 2, 4, true, 45, $JB$["assassin"]$JB$::jsonb, $JB$["spy"]$JB$::jsonb, $JB${"stress_attack": 50, "evade": 30, "resonate": 10, "ambient": 10}$JB$::jsonb, $JB$["resonate"]$JB$::jsonb, $Q$A memory of a memory. It does not have content – it has the shape where content was. {agent} recognizes the absence, not the thing.$Q$, $Q$Eine Erinnerung an eine Erinnerung. Sie hat keinen Inhalt – sie hat die Form, wo Inhalt war. {agent} erkennt die Abwesenheit, nicht das Ding.$Q$, $JB$["The fragment flickers. For a moment it wears {agent}'s posture.", "Something familiar in the echo. Not the memory – the act of remembering."]$JB$::jsonb, $JB$["Das Fragment flackert. Einen Moment lang trägt es {agent}s Haltung.", "Etwas Vertrautes im Echo. Nicht die Erinnerung – der Akt des Erinnerns."]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemies (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_deja_vu_phantom$Q$, $Q$Déjà-vu Phantom$Q$, $Q$Déjà-vu-Phantom$Q$, $Q$The Awakening$Q$, 2, 80, $Q$standard$Q$, $Q$propagandist$Q$, 3, 6, true, 20, $JB$["saboteur"]$JB$::jsonb, $JB$["propagandist", "spy"]$JB$::jsonb, $JB${"stress_attack": 40, "recognition": 30, "attack": 20, "ambient": 10}$JB$::jsonb, $JB$["recognition"]$JB$::jsonb, $Q$It is not here for the first time. It has always been in this room, waiting for the party to arrive again. Its movements are half a second ahead of expectation – as if the party remembers fighting it before the fight has begun.$Q$, $Q$Es ist nicht zum ersten Mal hier. Es war immer in diesem Raum und wartete darauf, dass die Gruppe wieder ankommt. Seine Bewegungen sind eine halbe Sekunde vor der Erwartung – als erinnerte sich die Gruppe an den Kampf, bevor er begonnen hat.$Q$, $JB$["The phantom repeats a gesture {agent} has not yet made.", "Déjà vu. The phantom was already there. It was always already there."]$JB$::jsonb, $JB$["Das Phantom wiederholt eine Geste, die {agent} noch nicht gemacht hat.", "Déjà vu. Das Phantom war bereits da. Es war immer bereits da."]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemies (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_consciousness_leech$Q$, $Q$Consciousness Leech$Q$, $Q$Bewusstseinsegel$Q$, $Q$The Awakening$Q$, 2, 60, $Q$standard$Q$, $Q$spy$Q$, 4, 5, true, 15, $JB$["propagandist"]$JB$::jsonb, $JB$["guardian", "assassin"]$JB$::jsonb, $JB${"attack": 40, "drain_awareness": 25, "stress_attack": 25, "ambient": 10}$JB$::jsonb, $JB$["drain_awareness"]$JB$::jsonb, $Q$Watts was right about this one. It functions perfectly without self-awareness – a philosophical zombie made operational. It does not think. It processes. And it is faster than anything that pauses to reflect.$Q$, $Q$Watts hatte Recht, was dieses betrifft. Es funktioniert einwandfrei ohne Selbstbewusstsein – ein philosophischer Zombie, operational. Es denkt nicht. Es verarbeitet. Und es ist schneller als alles, was innehält, um nachzudenken.$Q$, $JB$["The leech observes {agent}. Not with curiosity – with efficiency.", "It does not know it exists. This is its advantage."]$JB$::jsonb, $JB$["Der Egel beobachtet {agent}. Nicht mit Neugier – mit Effizienz.", "Es weiß nicht, dass es existiert. Das ist sein Vorteil."]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemies (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_repressed_sentinel$Q$, $Q$Repressed Sentinel$Q$, $Q$Verdrängungs­wächter$Q$, $Q$The Awakening$Q$, 4, 100, $Q$elite$Q$, $Q$guardian$Q$, 5, 7, true, 10, $JB$["spy", "infiltrator"]$JB$::jsonb, $JB$["propagandist"]$JB$::jsonb, $JB${"attack": 35, "suppress": 25, "stress_attack": 20, "defend": 10, "ambient": 10}$JB$::jsonb, $JB$["suppress"]$JB$::jsonb, $Q$The sentinel guards the threshold between conscious and unconscious. Ishiguro's mist made guardian – it exists to ensure the buried stays buried. It does not hate the party. It pities their need to know.$Q$, $Q$Der Wächter hütet die Schwelle zwischen Bewusstem und Unbewusstem. Ishiguros Nebel, zum Wächter geworden – er existiert, um sicherzustellen, dass das Vergrabene begraben bleibt. Er hasst die Gruppe nicht. Er bedauert ihr Bedürfnis zu wissen.$Q$, $JB$["The sentinel stands between {agent} and a memory {agent} cannot name.", "It makes no sound. Repression is always quiet."]$JB$::jsonb, $JB$["Der Wächter steht zwischen {agent} und einer Erinnerung, die {agent} nicht benennen kann.", "Er gibt keinen Laut. Verdrängung ist immer still."]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemies (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_the_repressed$Q$, $Q$The Repressed$Q$, $Q$Das Verdrängte$Q$, $Q$The Awakening$Q$, 6, 120, $Q$boss$Q$, $Q$guardian$Q$, 6, 9, false, 15, $JB$["assassin", "saboteur"]$JB$::jsonb, $JB$["spy", "propagandist"]$JB$::jsonb, $JB${"attack": 30, "resurface": 25, "stress_attack": 25, "suppress": 10, "ambient": 10}$JB$::jsonb, $JB$["resurface", "suppress"]$JB$::jsonb, $Q$A memory so painful it was buried by consensus. Not by one agent – by all of them simultaneously. It is not a monster. It is the truth that was too heavy to carry and too important to destroy. Jung's encounter with the Self, Tarkovsky's Room: it grants your true desire, not your stated one.$Q$, $Q$Eine Erinnerung so schmerzhaft, dass sie durch Konsens begraben wurde. Nicht von einem Agenten – von allen gleichzeitig. Es ist kein Monster. Es ist die Wahrheit, die zu schwer war, um sie zu tragen, und zu wichtig, um sie zu zerstören. Jungs Begegnung mit dem Selbst, Tarkowskis Raum: er gewährt den wahren Wunsch, nicht den ausgesprochenen.$Q$, $JB$["The Repressed does not attack. It surfaces. The damage is recognition.", "It has been here the entire dungeon. In every room, behind every memory.", "{agent} realizes: they knew. They always knew. They chose not to know."]$JB$::jsonb, $JB$["Das Verdrängte greift nicht an. Es taucht auf. Der Schaden ist Wiedererkennung.", "Es war das gesamte Dungeon hier. In jedem Raum, hinter jeder Erinnerung.", "{agent} erkennt: sie wussten es. Sie wussten es immer. Sie entschieden sich, es nicht zu wissen."]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_spawn_configs (id, archetype, units) VALUES ($Q$awakening_echo_drift_spawn$Q$, $Q$The Awakening$Q$, $JB$[{"template_id": "awakening_echo_fragment", "count": 2}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, units = EXCLUDED.units;
INSERT INTO dungeon_spawn_configs (id, archetype, units) VALUES ($Q$awakening_deja_vu_patrol_spawn$Q$, $Q$The Awakening$Q$, $JB$[{"template_id": "awakening_deja_vu_phantom", "count": 1}, {"template_id": "awakening_echo_fragment", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, units = EXCLUDED.units;
INSERT INTO dungeon_spawn_configs (id, archetype, units) VALUES ($Q$awakening_leech_hunt_spawn$Q$, $Q$The Awakening$Q$, $JB$[{"template_id": "awakening_consciousness_leech", "count": 1}, {"template_id": "awakening_echo_fragment", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, units = EXCLUDED.units;
INSERT INTO dungeon_spawn_configs (id, archetype, units) VALUES ($Q$awakening_deep_mind_spawn$Q$, $Q$The Awakening$Q$, $JB$[{"template_id": "awakening_consciousness_leech", "count": 1}, {"template_id": "awakening_deja_vu_phantom", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, units = EXCLUDED.units;
INSERT INTO dungeon_spawn_configs (id, archetype, units) VALUES ($Q$awakening_sentinel_spawn$Q$, $Q$The Awakening$Q$, $JB$[{"template_id": "awakening_repressed_sentinel", "count": 1}, {"template_id": "awakening_echo_fragment", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, units = EXCLUDED.units;
INSERT INTO dungeon_spawn_configs (id, archetype, units) VALUES ($Q$awakening_rest_ambush_spawn$Q$, $Q$The Awakening$Q$, $JB$[{"template_id": "awakening_echo_fragment", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, units = EXCLUDED.units;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_echo_drift$Q$, $Q$The Awakening$Q$, $Q$combat$Q$, 1, 3, 1, $Q$Fragments at the periphery. Not hostile – residual. Two echo fragments drift through the room, wearing postures borrowed from the party. They are memories of a memory – impressions with no original.$Q$, $Q$Fragmente an der Peripherie. Nicht feindlich – residual. Zwei Echofragmente driften durch den Raum und tragen Haltungen, die sie von der Gruppe geliehen haben. Erinnerungen an eine Erinnerung – Eindrücke ohne Original.$Q$, $Q$awakening_echo_drift_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_deja_vu_corridor$Q$, $Q$The Awakening$Q$, $Q$combat$Q$, 2, 4, 1, $Q$The corridor is familiar. The party has never been here. Both of these are true. A Déjà-vu Phantom occupies the center – its movements half a second ahead of expectation. An echo fragment trails behind, filling the gaps in the phantom's choreography.$Q$, $Q$Der Korridor ist vertraut. Die Gruppe war nie hier. Beides stimmt. Ein Déjà-vu-Phantom besetzt die Mitte – seine Bewegungen eine halbe Sekunde vor der Erwartung. Ein Echofragment folgt und füllt die Lücken in der Choreografie des Phantoms.$Q$, $Q$awakening_deja_vu_patrol_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_leech_hunt$Q$, $Q$The Awakening$Q$, $Q$combat$Q$, 2, 5, 1, $Q$Something in this room processes without perceiving. A Consciousness Leech – Watts's philosophical zombie made operational. It does not know it exists. This is its advantage. An echo fragment accompanies it, providing the self-awareness it lacks.$Q$, $Q$Etwas in diesem Raum verarbeitet, ohne wahrzunehmen. Ein Bewusstseinsegel – Watts' philosophischer Zombie, operational. Es weiß nicht, dass es existiert. Das ist sein Vorteil. Ein Echofragment begleitet es und stellt das Selbstbewusstsein bereit, das ihm fehlt.$Q$, $Q$awakening_leech_hunt_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_deep_mind_clash$Q$, $Q$The Awakening$Q$, $Q$combat$Q$, 3, 6, 1, $Q$Deeper. The consciousness here is denser, layered like a palimpsest. A Consciousness Leech and a Déjà-vu Phantom have found equilibrium – the zombie and the prophet, processing and predicting, neither aware that the other thinks differently.$Q$, $Q$Tiefer. Das Bewusstsein hier ist dichter, geschichtet wie ein Palimpsest. Ein Bewusstseinsegel und ein Déjà-vu-Phantom haben ein Gleichgewicht gefunden – der Zombie und der Prophet, verarbeitend und vorhersagend, keiner bewusst, dass der andere anders denkt.$Q$, $Q$awakening_deep_mind_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_sentinel_chamber$Q$, $Q$The Awakening$Q$, $Q$combat$Q$, 4, 7, 1, $Q$The threshold between remembered and repressed. A Sentinel guards it – Ishiguro's mist given form. It does not hate the party. It pities their need to know. An echo fragment drifts behind, a memory that was permitted to exist.$Q$, $Q$Die Schwelle zwischen Erinnertem und Verdrängtem. Ein Wächter hütet sie – Ishiguros Nebel, dem Form gegeben wurde. Er hasst die Gruppe nicht. Er bedauert ihr Bedürfnis zu wissen. Ein Echofragment driftet dahinter, eine Erinnerung, der gestattet wurde zu existieren.$Q$, $Q$awakening_sentinel_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_lucid_skirmish$Q$, $Q$The Awakening$Q$, $Q$combat$Q$, 3, 5, 1, $Q$The room recognizes the party. This is not a metaphor. The walls adjust. The light shifts to match a memory none of them can place. Two phantoms emerge from the adjustment – the room defending its version of events.$Q$, $Q$Der Raum erkennt die Gruppe. Das ist keine Metapher. Die Wände passen sich an. Das Licht verschiebt sich, um einer Erinnerung zu entsprechen, die keiner von ihnen einordnen kann. Zwei Phantome treten aus der Anpassung hervor – der Raum verteidigt seine Version der Geschehnisse.$Q$, $Q$awakening_deja_vu_patrol_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_the_mirror$Q$, $Q$The Awakening$Q$, $Q$encounter$Q$, 1, 3, 1, $Q$A surface. Not glass – not water – something that reflects without material. Each agent sees something different. Lem's mirror: we have no need of other worlds. We need mirrors.$Q$, $Q$Eine Oberfläche. Nicht Glas – nicht Wasser – etwas, das reflektiert ohne Material. Jeder Agent sieht etwas anderes. Lems Spiegel: wir brauchen keine anderen Welten. Wir brauchen Spiegel.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$mirror_study$Q$, $Q$aw_the_mirror$Q$, $Q$Study the reflection carefully (Spy)$Q$, $Q$Die Spiegelung sorgfältig studieren (Spion)$Q$, $Q$spy$Q$, -5, $JB${"awareness": 5}$JB$::jsonb, $JB${"awareness": 3}$JB$::jsonb, $JB${"stress": 10, "awareness": 8}$JB$::jsonb, $Q${agent} sees through the reflection to the mechanism. The mirror does not show the viewer – it shows what the viewer has forgotten about themselves. The awareness gained is not comfortable. It is precise.$Q$, $Q${agent} sieht durch die Spiegelung zum Mechanismus. Der Spiegel zeigt nicht den Betrachter – er zeigt, was der Betrachter über sich selbst vergessen hat. Das gewonnene Bewusstsein ist nicht angenehm. Es ist präzise.$Q$, $Q$The reflection holds {agent}'s gaze too long. When they look away, something in the reflection does not.$Q$, $Q$Die Spiegelung hält {agent}s Blick zu lange fest. Als sie wegschauen, tut etwas in der Spiegelung es nicht.$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$mirror_share$Q$, $Q$aw_the_mirror$Q$, $Q$Share what each agent sees (Propagandist)$Q$, $Q$Teilen, was jeder Agent sieht (Propagandist)$Q$, $Q$propagandist$Q$, -5, $JB${"awareness": -5, "stress_heal": 10}$JB$::jsonb, $JB${"awareness": -2}$JB$::jsonb, $JB${"awareness": 5, "stress": 5}$JB$::jsonb, $Q$Each agent describes their reflection. The descriptions overlap – same room, different memories. The act of sharing stabilizes what each agent sees alone. Sturgeon's bleshing: the gestalt perceives more clearly than any individual.$Q$, $Q$Jeder Agent beschreibt seine Spiegelung. Die Beschreibungen überlappen sich – derselbe Raum, unterschiedliche Erinnerungen. Das Teilen stabilisiert, was jeder Agent allein sieht. Sturgeons Bleshing: das Gestalt nimmt klarer wahr als jeder Einzelne.$Q$, $Q$The descriptions do not overlap. Each agent is alone in their perception. The mirror shows this, too.$Q$, $Q$Die Beschreibungen überlappen sich nicht. Jeder Agent ist allein in seiner Wahrnehmung. Der Spiegel zeigt auch das.$Q$, 1) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$mirror_pass$Q$, $Q$aw_the_mirror$Q$, $Q$Do not look. Move through.$Q$, $Q$Nicht hinsehen. Weitergehen.$Q$, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party passes. Orpheus's discipline. The mirror reflects their backs.$Q$, $Q$Die Gruppe geht weiter. Orpheus' Disziplin. Der Spiegel reflektiert ihre Rücken.$Q$, $Q$$Q$, $Q$$Q$, 2) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_the_familiar_room$Q$, $Q$The Awakening$Q$, $Q$encounter$Q$, 2, 4, 1, $Q$This room. The party has been here. Not in this dungeon – somewhere. The window was on the left. Or the right. The details resist settling. Proust's madeleine: the sensation arrives before the memory.$Q$, $Q$Dieser Raum. Die Gruppe war hier. Nicht in diesem Dungeon – irgendwo. Das Fenster war links. Oder rechts. Die Details weigern sich, sich festzulegen. Prousts Madeleine: die Empfindung kommt vor der Erinnerung.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$familiar_investigate$Q$, $Q$aw_the_familiar_room$Q$, $Q$Investigate what changed (Spy)$Q$, $Q$Untersuchen, was sich verändert hat (Spion)$Q$, $Q$spy$Q$, 0, $JB${"awareness": 3}$JB$::jsonb, $JB${"awareness": 2}$JB$::jsonb, $JB${"awareness": 8}$JB$::jsonb, $Q${agent} catalogs the differences. The window was on the left – now it is on the right. Neither is wrong. The memory is not replayed; it is reconstructed. The reconstruction reveals something about the one who reconstructs.$Q$, $Q${agent} katalogisiert die Unterschiede. Das Fenster war links – jetzt ist es rechts. Keines ist falsch. Die Erinnerung wird nicht wiedergegeben; sie wird rekonstruiert. Die Rekonstruktion verrät etwas über den, der rekonstruiert.$Q$, $Q$The details shift faster than {agent} can track. Funes's curse: too much detail, no abstraction. The room fills with almost-contiguous memories.$Q$, $Q$Die Details verschieben sich schneller, als {agent} folgen kann. Funes' Fluch: zu viel Detail, keine Abstraktion. Der Raum füllt sich mit fast-angrenzenden Erinnerungen.$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$familiar_accept$Q$, $Q$aw_the_familiar_room$Q$, $Q$Accept the familiarity without questioning$Q$, $Q$Die Vertrautheit akzeptieren, ohne zu fragen$Q$, NULL, 0, $JB${"stress_heal": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party accepts. The room settles. Tarkovsky's lesson: everything depends not on the Zone, but on the visitor.$Q$, $Q$Die Gruppe akzeptiert. Der Raum beruhigt sich. Tarkowskis Lektion: alles hängt nicht von der Zone ab, sondern vom Besucher.$Q$, $Q$$Q$, $Q$$Q$, 1) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_the_two_clocks$Q$, $Q$The Awakening$Q$, $Q$encounter$Q$, 2, 5, 1, $Q$Time is not uniform here. Kafka's two clocks: the inner one runs crazily on at an inhuman pace, the outer one limps along. The party experiences both. Actions in this room have consequences at different speeds.$Q$, $Q$Die Zeit ist hier nicht einheitlich. Kafkas zwei Uhren: die innere rennt wahnsinnig weiter in unmenschlichem Tempo, die äußere hinkt. Die Gruppe erlebt beides. Handlungen in diesem Raum haben Konsequenzen in unterschiedlichen Geschwindigkeiten.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$clocks_synchronize$Q$, $Q$aw_the_two_clocks$Q$, $Q$Attempt to synchronize the clocks (Guardian)$Q$, $Q$Versuchen, die Uhren zu synchronisieren (Wächter)$Q$, $Q$guardian$Q$, 0, $JB${"awareness": -5, "stress_heal": 15}$JB$::jsonb, $JB${"awareness": -2}$JB$::jsonb, $JB${"awareness": 10, "stress": 10}$JB$::jsonb, $Q${agent} grounds the party in shared time. The clocks align, briefly. In that moment of synchronization, the room is perfectly clear – every detail sharp, every memory precise. Then the drift resumes.$Q$, $Q${agent} erdet die Gruppe in gemeinsamer Zeit. Die Uhren gleichen sich an, kurz. In diesem Moment der Synchronisation ist der Raum vollkommen klar – jedes Detail scharf, jede Erinnerung präzise. Dann setzt die Drift wieder ein.$Q$, $Q$The clocks split further. What else can happen but that the two worlds split apart?$Q$, $Q$Die Uhren entfernen sich weiter. Was kann sonst geschehen, als dass die zwei Welten auseinanderbrechen?$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$clocks_inner$Q$, $Q$aw_the_two_clocks$Q$, $Q$Follow the inner clock deeper (Infiltrator)$Q$, $Q$Der inneren Uhr tiefer folgen (Infiltrator)$Q$, $Q$infiltrator$Q$, 5, $JB${"awareness": 8, "loot_tier": 1}$JB$::jsonb, $JB${"awareness": 5}$JB$::jsonb, $JB${"awareness": 12, "stress": 15}$JB$::jsonb, $Q${agent} follows the faster clock. Time compresses. What takes minutes outside takes seconds inside. In the compressed time, {agent} perceives something the outer clock would never reveal.$Q$, $Q${agent} folgt der schnelleren Uhr. Die Zeit komprimiert sich. Was draußen Minuten dauert, dauert drinnen Sekunden. In der komprimierten Zeit nimmt {agent} etwas wahr, das die äußere Uhr nie enthüllen würde.$Q$, $Q$The inner clock is too fast. {agent} is swept along at an inhuman pace. The return to outer time is disorienting.$Q$, $Q$Die innere Uhr ist zu schnell. {agent} wird in unmenschlichem Tempo mitgerissen. Die Rückkehr zur äußeren Zeit ist desorientierend.$Q$, 1) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$clocks_wait$Q$, $Q$aw_the_two_clocks$Q$, $Q$Wait for the moment to pass$Q$, $Q$Warten, bis der Moment vergeht$Q$, NULL, 0, $JB${"awareness": 2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The clocks drift past each other. The room normalizes. The party is not unchanged.$Q$, $Q$Die Uhren driften aneinander vorbei. Der Raum normalisiert sich. Die Gruppe ist nicht unverändert.$Q$, $Q$$Q$, $Q$$Q$, 2) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_the_absent_memory$Q$, $Q$The Awakening$Q$, $Q$encounter$Q$, 3, 6, 1, $Q$A room with a gap. Not a hole – a smooth, clean absence. Something was here. The dungeon remembers that it forgets. Ogawa's memory police: first the emotional connection vanishes, then the physical evidence. This room is at stage two.$Q$, $Q$Ein Raum mit einer Lücke. Kein Loch – eine glatte, saubere Abwesenheit. Etwas war hier. Das Dungeon erinnert sich, dass es vergisst. Ogawas Gedächtnispolizei: erst verschwindet die emotionale Verbindung, dann der physische Beweis. Dieser Raum ist bei Stufe zwei.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$absent_reconstruct$Q$, $Q$aw_the_absent_memory$Q$, $Q$Reconstruct what was here (Propagandist)$Q$, $Q$Rekonstruieren, was hier war (Propagandist)$Q$, $Q$propagandist$Q$, 5, $JB${"awareness": 5, "loot_tier": 1}$JB$::jsonb, $JB${"awareness": 3}$JB$::jsonb, $JB${"awareness": 10, "stress": 10}$JB$::jsonb, $Q${agent} fills the gap. Not with the original memory – that is gone. With a reconstruction. The reconstruction becomes real. Borges's hronir: objects materialized by expectation. The dungeon accepts the substitute.$Q$, $Q${agent} füllt die Lücke. Nicht mit der ursprünglichen Erinnerung – die ist weg. Mit einer Rekonstruktion. Die Rekonstruktion wird real. Borges' Hronir: Objekte, materialisiert durch Erwartung. Das Dungeon akzeptiert das Substitut.$Q$, $Q$The gap resists reconstruction. The absence is informative: what the dungeon cannot remember, it cannot forgive.$Q$, $Q$Die Lücke widersteht der Rekonstruktion. Die Abwesenheit ist informativ: was das Dungeon nicht erinnern kann, kann es nicht vergeben.$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$absent_accept$Q$, $Q$aw_the_absent_memory$Q$, $Q$Accept the absence as it is$Q$, $Q$Die Abwesenheit akzeptieren, wie sie ist$Q$, NULL, 0, $JB${"awareness": -3, "stress_heal": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$Ishiguro's wisdom: some memories were buried for reasons. The party respects the gap. The gap respects the party.$Q$, $Q$Ishiguros Weisheit: manche Erinnerungen wurden aus Gründen begraben. Die Gruppe respektiert die Lücke. Die Lücke respektiert die Gruppe.$Q$, $Q$$Q$, $Q$$Q$, 1) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_the_humming$Q$, $Q$The Awakening$Q$, $Q$encounter$Q$, 3, 99, 1, $Q$From somewhere: a humming. The likes of which the party has never heard. Not really humming – the singing of the most distant, of the most utterly distant, voices. Kafka's Castle telephone: this humming is the only real and reliable thing. Everything else is deceptive.$Q$, $Q$Von irgendwo: ein Summen. Wie es die Gruppe noch nie gehört hat. Nicht wirklich Summen – das Singen der fernsten, der allerallerfernsten Stimmen. Kafkas Schlosstelefon: dieses Summen ist das einzig Reale und Verlässliche. Alles andere ist Täuschung.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$humming_listen$Q$, $Q$aw_the_humming$Q$, $Q$Listen deeply (Spy)$Q$, $Q$Tief hinhören (Spion)$Q$, $Q$spy$Q$, 5, $JB${"awareness": 10, "stress_heal": 20}$JB$::jsonb, $JB${"awareness": 8, "stress_heal": 10}$JB$::jsonb, $JB${"awareness": 15, "stress": 15}$JB$::jsonb, $Q$The humming resolves. Not into words – into recognition. {agent} hears the dungeon's voice and understands: it is the party's own collective voice, heard from the outside. Jaynes's bicameral mind: the gods were always us.$Q$, $Q$Das Summen löst sich auf. Nicht in Worte – in Wiedererkennung. {agent} hört die Stimme des Dungeons und versteht: es ist die eigene kollektive Stimme der Gruppe, von außen gehört. Jaynes' zweikammeriger Geist: die Götter waren immer wir.$Q$, $Q$The humming overwhelms. Too many voices, too distant, too simultaneous. Funes's garbage heap. The party retreats from the signal.$Q$, $Q$Das Summen überwältigt. Zu viele Stimmen, zu fern, zu gleichzeitig. Funes' Müllhalde. Die Gruppe weicht vor dem Signal zurück.$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$humming_block$Q$, $Q$aw_the_humming$Q$, $Q$Block it out (Guardian)$Q$, $Q$Es ausblenden (Wächter)$Q$, $Q$guardian$Q$, -5, $JB${"awareness": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${"awareness": 5}$JB$::jsonb, $Q${agent} maintains the boundary. The humming recedes. The dungeon notes the refusal without judgment.$Q$, $Q${agent} hält die Grenze aufrecht. Das Summen lässt nach. Das Dungeon vermerkt die Weigerung ohne Urteil.$Q$, $Q$The humming finds a way through. Not through the walls – through the awareness itself.$Q$, $Q$Das Summen findet einen Weg hindurch. Nicht durch die Wände – durch das Bewusstsein selbst.$Q$, 1) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_threshold_gate$Q$, $Q$The Awakening$Q$, $Q$elite$Q$, 4, 6, 1, $Q$Before the Law. A gate between remembered and repressed. The Sentinel guards it – not with force, but with pity. This door was made only for the party. The Sentinel has waited their entire descent.$Q$, $Q$Vor dem Gesetz. Ein Tor zwischen Erinnertem und Verdrängtem. Der Wächter hütet es – nicht mit Gewalt, sondern mit Mitleid. Dieses Tor wurde nur für die Gruppe gemacht. Der Wächter hat ihren gesamten Abstieg gewartet.$Q$, $Q$awakening_sentinel_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_the_repressed_boss$Q$, $Q$The Awakening$Q$, $Q$boss$Q$, 4, 99, 1, $Q$The room at the center. Tarkovsky's Room: it grants your true desire, not your stated one. The Repressed has been here the entire dungeon – in every room, behind every memory, inside every recognition. It is not a monster. It is the truth that was too heavy to carry and too important to destroy.$Q$, $Q$Der Raum in der Mitte. Tarkowskis Raum: er gewährt den wahren Wunsch, nicht den ausgesprochenen. Das Verdrängte war das gesamte Dungeon hier – in jedem Raum, hinter jeder Erinnerung, in jeder Wiedererkennung. Es ist kein Monster. Es ist die Wahrheit, die zu schwer war, um sie zu tragen, und zu wichtig, um sie zu zerstören.$Q$, $Q$awakening_sentinel_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_quiet_layer$Q$, $Q$The Awakening$Q$, $Q$rest$Q$, 1, 99, 1, $Q$A stratum of consciousness that is still. Not empty – calm. Like the pause between breaths. The dungeon's awareness rests here too. For a moment, the observer and the observed share the same silence.$Q$, $Q$Eine Schicht des Bewusstseins, die still ist. Nicht leer – ruhig. Wie die Pause zwischen Atemzügen. Das Bewusstsein des Dungeons ruht hier ebenfalls. Für einen Moment teilen der Beobachter und das Beobachtete dieselbe Stille.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$quiet_rest$Q$, $Q$aw_quiet_layer$Q$, $Q$Rest in the quiet layer$Q$, $Q$In der stillen Schicht rasten$Q$, NULL, 0, $JB${"stress_heal": 40, "awareness": -5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$Silence. Not absence of sound – presence of peace. The awareness recedes like a tide. The party is not diminished. They are grounded.$Q$, $Q$Stille. Nicht Abwesenheit von Klang – Anwesenheit von Frieden. Das Bewusstsein zieht sich zurück wie eine Gezeit. Die Gruppe ist nicht vermindert. Sie ist geerdet.$Q$, $Q$$Q$, $Q$$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_forgetting_pool$Q$, $Q$The Awakening$Q$, $Q$rest$Q$, 3, 99, 1, $Q$Lethe. A pool of deliberate forgetting. Not a loss – a choice. The Oracle of Trophonius demands it: drink from Lethe first, to forget all prior thoughts. Then from Mnemosyne, to remember what you will see. Both rivers, sequentially.$Q$, $Q$Lethe. Ein Becken des absichtlichen Vergessens. Kein Verlust – eine Wahl. Das Orakel des Trophonios verlangt es: trinke zuerst aus Lethe, um alle vorherigen Gedanken zu vergessen. Dann aus Mnemosyne, um zu erinnern, was du sehen wirst. Beide Flüsse, nacheinander.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$pool_drink$Q$, $Q$aw_forgetting_pool$Q$, $Q$Drink from the pool (reduces awareness significantly)$Q$, $Q$Aus dem Becken trinken (senkt Bewusstsein erheblich)$Q$, NULL, 0, $JB${"stress_heal": 25, "awareness": -15, "stress": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party drinks. Awareness recedes sharply. Some memories blur. Some details soften. The trade is not free – forgetting is its own kind of labor. But the mind is lighter.$Q$, $Q$Die Gruppe trinkt. Das Bewusstsein geht scharf zurück. Manche Erinnerungen werden unscharf. Manche Details weicher. Der Tausch ist nicht kostenlos – Vergessen ist seine eigene Art von Arbeit. Aber der Geist ist leichter.$Q$, $Q$$Q$, $Q$$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_crystallized_memory$Q$, $Q$The Awakening$Q$, $Q$treasure$Q$, 1, 99, 1, $Q$Consciousness, solidified. A lieu de mémoire – Nora's concept: a place where memory crystallizes because history would dissolve it. The artifact holds what the dungeon chose to preserve.$Q$, $Q$Bewusstsein, verfestigt. Ein Lieu de Mémoire – Noras Konzept: ein Ort, an dem Erinnerung kristallisiert, weil Geschichte sie auflösen würde. Das Artefakt bewahrt, was das Dungeon zu bewahren wählte.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$crystal_take$Q$, $Q$aw_crystallized_memory$Q$, $Q$Take the crystallized memory$Q$, $Q$Die kristallisierte Erinnerung nehmen$Q$, NULL, 0, $JB${"loot_tier": 1, "awareness": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The crystal releases warmth on contact. Not physical warmth – the warmth of recognition. The party has gained something. The dungeon has lost something.$Q$, $Q$Der Kristall gibt bei Berührung Wärme ab. Nicht physische Wärme – die Wärme der Wiedererkennung. Die Gruppe hat etwas gewonnen. Das Dungeon hat etwas verloren.$Q$, $Q$$Q$, $Q$$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounters (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$aw_the_archive$Q$, $Q$The Awakening$Q$, $Q$treasure$Q$, 2, 99, 1, $Q$An archive. Not of documents – of impressions. Each shelf holds a sensation: the smell of rain on warm stone, the sound of a name almost remembered, the weight of a decision not yet made. Bergson's cone of memory: the totality of experience, compressed into accessible form.$Q$, $Q$Ein Archiv. Nicht aus Dokumenten – aus Eindrücken. Jedes Regal hält eine Empfindung: den Geruch von Regen auf warmem Stein, den Klang eines fast erinnerten Namens, das Gewicht einer noch nicht getroffenen Entscheidung. Bergsons Erinnerungskegel: die Gesamtheit der Erfahrung, komprimiert in zugängliche Form.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$archive_browse$Q$, $Q$aw_the_archive$Q$, $Q$Browse the archive carefully$Q$, $Q$Das Archiv sorgfältig durchsehen$Q$, NULL, 0, $JB${"loot_tier": 2, "awareness": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party selects carefully. Not everything. To think is to forget differences, to generalize, to make abstractions. The archive rewards selection over completeness.$Q$, $Q$Die Gruppe wählt sorgfältig. Nicht alles. Denken heißt Unterschiede vergessen, verallgemeinern, abstrahieren. Das Archiv belohnt Auswahl gegenüber Vollständigkeit.$Q$, $Q$$Q$, $Q$$Q$, 0) ON CONFLICT (id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_echo_trace$Q$, $Q$Echo Trace$Q$, $Q$Echospur$Q$, 1, $Q$stress_heal$Q$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $Q$A trace of a memory that was not the party's. Handling it calms something that was not disturbed.$Q$, $Q$Eine Spur einer Erinnerung, die nicht der Gruppe gehörte. Sie zu berühren beruhigt etwas, das nicht gestört war.$Q$, 30, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_deja_vu_fragment$Q$, $Q$Déjà-vu Fragment$Q$, $Q$Déjà-vu-Fragment$Q$, 1, $Q$memory$Q$, $JB${"importance": 4, "content_en": "Learned to distinguish memory from perception", "content_de": "Gelernt, Erinnerung von Wahrnehmung zu unterscheiden"}$JB$::jsonb, $Q$A crystallized moment of recognition that predates experience.$Q$, $Q$Ein kristallisierter Moment der Wiedererkennung, der der Erfahrung vorausgeht.$Q$, 25, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_lucid_lens$Q$, $Q$Lucid Lens$Q$, $Q$Luzide Linse$Q$, 1, $Q$dungeon_buff$Q$, $JB${"aptitude": "spy", "bonus_pct": 5}$JB$::jsonb, $Q$Perception sharpened by awareness. Spy checks +5%.$Q$, $Q$Wahrnehmung geschärft durch Bewusstsein. Spion-Proben +5%.$Q$, 25, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_grounding_stone$Q$, $Q$Grounding Stone$Q$, $Q$Erdungsstein$Q$, 1, $Q$dungeon_buff$Q$, $JB${"aptitude": "guardian", "bonus_pct": 5}$JB$::jsonb, $Q$An anchor for identity. Guardian checks +5%.$Q$, $Q$Ein Anker für Identität. Wächter-Proben +5%.$Q$, 20, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_mnemosyne_draught$Q$, $Q$Mnemosyne Draught$Q$, $Q$Mnemosyne-Trunk$Q$, 2, $Q$stress_heal$Q$, $JB${"stress_heal": 100, "when": "after_dungeon"}$JB$::jsonb, $Q$From the river of memory. Drinking it restores what the descent consumed. The taste is of recognition.$Q$, $Q$Aus dem Fluss der Erinnerung. Ihn zu trinken stellt wieder her, was der Abstieg verbrauchte. Der Geschmack ist Wiedererkennung.$Q$, 30, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_collective_impression$Q$, $Q$Collective Impression$Q$, $Q$Kollektiver Eindruck$Q$, 2, $Q$memory$Q$, $JB${"importance": 6, "content_en": "Experienced shared consciousness – perceived through multiple perspectives simultaneously", "content_de": "Kollektives Bewusstsein erfahren – gleichzeitig durch mehrere Perspektiven wahrgenommen"}$JB$::jsonb, $Q$A memory that belongs to no single agent but to the party as gestalt.$Q$, $Q$Eine Erinnerung, die keinem einzelnen Agenten gehört, sondern der Gruppe als Gestalt.$Q$, 25, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_philemon_whisper$Q$, $Q$Philemon's Whisper$Q$, $Q$Philemons Flüstern$Q$, 2, $Q$dungeon_buff$Q$, $JB${"aptitude": "propagandist", "bonus_pct": 10}$JB$::jsonb, $Q$Thoughts are like animals in the forest – not generated by the thinker. Propagandist checks +10%.$Q$, $Q$Gedanken sind wie Tiere im Wald – nicht vom Denker erzeugt. Propagandist-Proben +10%.$Q$, 25, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_zone_map$Q$, $Q$Zone Map$Q$, $Q$Zonenkarte$Q$, 2, $Q$dungeon_buff$Q$, $JB${"aptitude": "infiltrator", "bonus_pct": 10}$JB$::jsonb, $Q$Everything depends not on the Zone, but on the visitor. A map of the consciousness topology. Infiltrator checks +10%.$Q$, $Q$Alles hängt nicht von der Zone ab, sondern vom Besucher. Eine Karte der Bewusstseinstopologie. Infiltrator-Proben +10%.$Q$, 20, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_insight$Q$, $Q$Awakening Insight$Q$, $Q$Erwachens-Erkenntnis$Q$, 3, $Q$personality_modifier$Q$, $JB${"big_five_delta": 0.1, "player_choice": true}$JB$::jsonb, $Q$The deepest insight. A shift in personality so fundamental it cannot be unlearned. Modify one agent's Big Five personality dimension by 0.1. The choice of which dimension is yours – and irreversible.$Q$, $Q$Die tiefste Erkenntnis. Eine Persönlichkeitsverschiebung so fundamental, dass sie nicht verlernt werden kann. Verändere eine Big-Five-Persönlichkeitsdimension eines Agenten um 0.1. Die Wahl der Dimension ist deine – und unwiderruflich.$Q$, 40, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_individuation_key$Q$, $Q$Individuation Key$Q$, $Q$Individuationsschlüssel$Q$, 3, $Q$aptitude_boost$Q$, $JB${"aptitude": "spy", "boost": 1}$JB$::jsonb, $Q$Jung's key to individuation: the conscious integration of unconscious material. Perception permanently deepened. Spy aptitude +1.$Q$, $Q$Jungs Schlüssel zur Individuation: die bewusste Integration unbewussten Materials. Wahrnehmung dauerhaft vertieft. Spion-Aptitude +1.$Q$, 35, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$awakening_collective_resonance$Q$, $Q$Collective Resonance$Q$, $Q$Kollektive Resonanz$Q$, 3, $Q$simulation_modifier$Q$, $JB${"morale_boost": true, "duration_ticks": 10, "boost_amount": 0.15, "description_en": "The collective consciousness bleeds into the simulation. All agents gain +15% morale for 10 heartbeat ticks.", "description_de": "Das kollektive Bewusstsein sickert in die Simulation. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks."}$JB$::jsonb, $Q$The collective consciousness resonates outward from the dungeon into the simulation itself. All agents gain +15% morale for 10 heartbeat ticks.$Q$, $Q$Das kollektive Bewusstsein resoniert nach außen vom Dungeon in die Simulation selbst. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks.$Q$, 25, $Q$The Awakening$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Awakening$Q$, $Q$The threshold hums. Not mechanically – the singing of the most distant, of the most utterly distant, voices. Kafka's telephone: this is the only real and reliable thing. Everything beyond is reconstruction.$Q$, $Q$Die Schwelle summt. Nicht mechanisch – das Singen der fernsten, der allerallerfernsten Stimmen. Kafkas Telefon: dies ist das einzig Reale und Verlässliche. Alles dahinter ist Rekonstruktion.$Q$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Awakening$Q$, $Q$The entrance is familiar. {agent} has not been here. The familiarity is not personal – it is collective. Something in the architecture recognizes the species, not the individual.$Q$, $Q$Der Eingang ist vertraut. {agent} war nicht hier. Die Vertrautheit ist nicht persönlich – sie ist kollektiv. Etwas in der Architektur erkennt die Spezies, nicht das Individuum.$Q$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Awakening$Q$, $Q$A mirror at the entrance. Not glass. Not water. Something that reflects without material. {agent}'s reflection arrives half a second late.$Q$, $Q$Ein Spiegel am Eingang. Nicht Glas. Nicht Wasser. Etwas, das ohne Material reflektiert. {agent}s Spiegelung kommt eine halbe Sekunde zu spät.$Q$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Awakening$Q$, $Q$Beyond the threshold, the air changes. Not temperature – density of attention. Something is already aware that the party has arrived. It was aware before they decided to enter.$Q$, $Q$Hinter der Schwelle ändert sich die Luft. Nicht die Temperatur – die Dichte der Aufmerksamkeit. Etwas ist sich bereits bewusst, dass die Gruppe angekommen ist. Es war bewusst, bevor sie sich entschieden einzutreten.$Q$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Awakening$Q$, $Q$The descent begins. Not physically – the floor is level. The descent is into layers of consciousness. Bergson's cone: the summit is the narrow present. The base is the totality of memory.$Q$, $Q$Der Abstieg beginnt. Nicht physisch – der Boden ist eben. Der Abstieg geht in Schichten des Bewusstseins. Bergsons Kegel: der Gipfel ist die enge Gegenwart. Die Basis ist die Gesamtheit der Erinnerung.$Q$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_mirror_shard$Q$, $Q$The Awakening$Q$, $Q$Mirror Shard$Q$, $Q$Spiegelscherbe$Q$, $JB${"discovery": {"text_en": "A shard of mirror. It reflects the room, but the reflection is slightly ahead of real time.", "text_de": "Eine Spiegelscherbe. Sie reflektiert den Raum, aber die Spiegelung ist der Echtzeit leicht voraus."}, "echo": {"text_en": "{agent} looks into the shard. The shard looks back. Neither blinks first.", "text_de": "{agent} blickt in die Scherbe. Die Scherbe blickt zurück. Keiner blinzelt zuerst."}, "mutation": {"text_en": "The shard now reflects a room that does not match this one. The other room is more complete.", "text_de": "Die Scherbe reflektiert jetzt einen Raum, der nicht mit diesem übereinstimmt. Der andere Raum ist vollständiger."}, "climax": {"text_en": "The shard reflects nothing. Or everything. The distinction has stopped mattering.", "text_de": "Die Scherbe reflektiert nichts. Oder alles. Die Unterscheidung hat aufgehört, wichtig zu sein."}}$JB$::jsonb, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_philemon_feather$Q$, $Q$The Awakening$Q$, $Q$Philemon's Feather$Q$, $Q$Philemons Feder$Q$, $JB${"discovery": {"text_en": "A feather. Iridescent. It does not belong to any bird the party can name.", "text_de": "Eine Feder. Schillernd. Sie gehört keinem Vogel, den die Gruppe benennen kann."}, "echo": {"text_en": "{agent} picks up the feather. A thought arrives that {agent} did not generate. Jung's lesson: thoughts are animals in the forest.", "text_de": "{agent} hebt die Feder auf. Ein Gedanke kommt, den {agent} nicht erzeugt hat. Jungs Lektion: Gedanken sind Tiere im Wald."}, "mutation": {"text_en": "The feather writes. Not with ink – with attention. Where it rests, the surface remembers.", "text_de": "Die Feder schreibt. Nicht mit Tinte – mit Aufmerksamkeit. Wo sie liegt, erinnert sich die Oberfläche."}, "climax": {"text_en": "The feather is the party's own thought, externalized. Philemon was always the party's own mind, speaking from the outside.", "text_de": "Die Feder ist der eigene Gedanke der Gruppe, externalisiert. Philemon war immer der eigene Geist der Gruppe, von außen sprechend."}}$JB$::jsonb, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_madeleine$Q$, $Q$The Awakening$Q$, $Q$The Madeleine$Q$, $Q$Die Madeleine$Q$, $JB${"discovery": {"text_en": "A small object. Its significance is not in its form but in its sensation. Touching it triggers something involuntary.", "text_de": "Ein kleines Objekt. Seine Bedeutung liegt nicht in seiner Form, sondern in seiner Empfindung. Es zu berühren löst etwas Unwillkürliches aus."}, "echo": {"text_en": "{agent} holds the madeleine. A memory surfaces – not from {agent}'s history. From the dungeon's.", "text_de": "{agent} hält die Madeleine. Eine Erinnerung taucht auf – nicht aus {agent}s Geschichte. Aus der des Dungeons."}, "mutation": {"text_en": "The madeleine has changed texture. It now feels like every significant object {agent} has ever touched.", "text_de": "Die Madeleine hat ihre Textur verändert. Sie fühlt sich jetzt an wie jedes bedeutsame Objekt, das {agent} je berührt hat."}, "climax": {"text_en": "The madeleine dissolves on contact. Proust's revelation: this essence was not in the party. It was the party.", "text_de": "Die Madeleine löst sich bei Berührung auf. Prousts Offenbarung: diese Essenz war nicht in der Gruppe. Sie war die Gruppe."}}$JB$::jsonb, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_two_clocks$Q$, $Q$The Awakening$Q$, $Q$The Two Clocks$Q$, $Q$Die Zwei Uhren$Q$, $JB${"discovery": {"text_en": "Two clocks on the wall. They show different times. Both are correct.", "text_de": "Zwei Uhren an der Wand. Sie zeigen unterschiedliche Zeiten. Beide sind korrekt."}, "echo": {"text_en": "{agent} checks both clocks. The gap between them has widened. The inner one runs crazily on.", "text_de": "{agent} prüft beide Uhren. Der Abstand zwischen ihnen hat sich vergrößert. Die innere rennt wahnsinnig weiter."}, "mutation": {"text_en": "The outer clock has stopped. The inner clock accelerates. What else can happen but that the two worlds split apart?", "text_de": "Die äußere Uhr ist stehen geblieben. Die innere Uhr beschleunigt. Was kann sonst geschehen, als dass die zwei Welten auseinanderbrechen?"}, "climax": {"text_en": "Both clocks show the same time. The party cannot tell which clock yielded.", "text_de": "Beide Uhren zeigen dieselbe Zeit. Die Gruppe kann nicht sagen, welche Uhr nachgegeben hat."}}$JB$::jsonb, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_cave_shadow$Q$, $Q$The Awakening$Q$, $Q$The Cave Shadow$Q$, $Q$Der Höhlenschatten$Q$, $JB${"discovery": {"text_en": "A shadow on the wall. It moves independently of any light source. Plato's warning: the freed prisoner cannot see the fire.", "text_de": "Ein Schatten an der Wand. Er bewegt sich unabhängig von jeder Lichtquelle. Platons Warnung: der befreite Gefangene kann das Feuer nicht sehen."}, "echo": {"text_en": "{agent} steps between the shadow and the wall. The shadow does not change. {agent} is not casting it.", "text_de": "{agent} tritt zwischen den Schatten und die Wand. Der Schatten ändert sich nicht. {agent} wirft ihn nicht."}, "mutation": {"text_en": "The shadow now shows events that are happening in other rooms. Higher consciousness does not add – it replaces.", "text_de": "Der Schatten zeigt jetzt Ereignisse, die in anderen Räumen geschehen. Höheres Bewusstsein fügt nicht hinzu – es ersetzt."}, "climax": {"text_en": "The shadow is the party. The party is the shadow. The wall was always the same side.", "text_de": "Der Schatten ist die Gruppe. Die Gruppe ist der Schatten. Die Wand war immer dieselbe Seite."}}$JB$::jsonb, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_empathy_box$Q$, $Q$The Awakening$Q$, $Q$The Empathy Box$Q$, $Q$Die Empathiebox$Q$, $JB${"discovery": {"text_en": "A device with handles. Dick's empathy box. Grasp the handles and enter shared consciousness.", "text_de": "Ein Gerät mit Griffen. Dicks Empathiebox. Greife die Griffe und betrete das gemeinsame Bewusstsein."}, "echo": {"text_en": "{agent} touches the handles. For a moment: every agent's perception, simultaneously. The moment passes. The memory persists.", "text_de": "{agent} berührt die Griffe. Für einen Moment: die Wahrnehmung jedes Agenten, gleichzeitig. Der Moment vergeht. Die Erinnerung bleibt."}, "mutation": {"text_en": "The handles are warm. Someone else is grasping them from the other side. Someone who does not exist yet.", "text_de": "Die Griffe sind warm. Jemand anderes greift sie von der anderen Seite. Jemand, der noch nicht existiert."}, "climax": {"text_en": "The box is empty. The shared consciousness no longer requires a device. It requires only the party.", "text_de": "Die Box ist leer. Das geteilte Bewusstsein benötigt kein Gerät mehr. Es benötigt nur die Gruppe."}}$JB$::jsonb, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_unicorn_skull$Q$, $Q$The Awakening$Q$, $Q$The Unicorn Skull$Q$, $Q$Der Einhornschädel$Q$, $JB${"discovery": {"text_en": "A skull. Not from any creature in the simulation's taxonomy. Murakami's dreamreading: extract memories from artifacts.", "text_de": "Ein Schädel. Von keiner Kreatur in der Taxonomie der Simulation. Murakamis Traumlesen: Erinnerungen aus Artefakten extrahieren."}, "echo": {"text_en": "{agent} holds the skull. Old dreams leak through: images without source, feelings without cause.", "text_de": "{agent} hält den Schädel. Alte Träume sickern durch: Bilder ohne Quelle, Gefühle ohne Ursache."}, "mutation": {"text_en": "The skull is heavier. It now contains the party's own dreams, absorbed without permission.", "text_de": "Der Schädel ist schwerer. Er enthält jetzt die eigenen Träume der Gruppe, absorbiert ohne Erlaubnis."}, "climax": {"text_en": "The skull speaks. Not in words. In recognition. The party's own subconscious, externalized as bone.", "text_de": "Der Schädel spricht. Nicht in Worten. In Wiedererkennung. Das eigene Unterbewusste der Gruppe, externalisiert als Knochen."}}$JB$::jsonb, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, name_en, name_de, phases, sort_order) VALUES ($Q$awakening_doorkeeper$Q$, $Q$The Awakening$Q$, $Q$The Doorkeeper$Q$, $Q$Der Türhüter$Q$, $JB${"discovery": {"text_en": "A figure beside an open door. The figure does not block entry. The door was always open. It was made only for the party.", "text_de": "Eine Gestalt neben einer offenen Tür. Die Gestalt versperrt den Eintritt nicht. Die Tür war immer offen. Sie wurde nur für die Gruppe gemacht."}, "echo": {"text_en": "{agent} asks the doorkeeper a question. The doorkeeper smiles. All barriers are self-imposed.", "text_de": "{agent} stellt dem Türhüter eine Frage. Der Türhüter lächelt. Alle Barrieren sind selbst auferlegt."}, "mutation": {"text_en": "The doorkeeper has aged. The door has not. The doorkeeper has been waiting for the party's entire existence.", "text_de": "Der Türhüter ist gealtert. Die Tür nicht. Der Türhüter hat auf die Gruppe gewartet seit ihrer gesamten Existenz."}, "climax": {"text_en": "The doorkeeper steps aside. There was never a barrier. There was only the party's belief in one.", "text_de": "Der Türhüter tritt zur Seite. Es gab nie eine Barriere. Es gab nur den Glauben der Gruppe an eine."}}$JB$::jsonb, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 0, $Q$The consciousness sleeps.$Q$, $Q$Das Bewusstsein schläft.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 1, $Q$The consciousness stirs.$Q$, $Q$Das Bewusstsein regt sich.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 2, $Q$The consciousness perceives.$Q$, $Q$Das Bewusstsein nimmt wahr.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 3, $Q$The consciousness remembers.$Q$, $Q$Das Bewusstsein erinnert sich.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
